```csharp
using System;
using System.Collections;

class Program
{
    static void Main()
    {
        Queue numbers = new Queue();

        // Enqueue items to the Queue
        numbers.Enqueue(1);
        numbers.Enqueue(2);
        numbers.Enqueue(3);

        // Peek at the first item in the Queue
        Console.WriteLine("Peek first item: " + numbers.Peek());

        // Dequeue items from the Queue
        Console.WriteLine("Dequeue: " + numbers.Dequeue());
        Console.WriteLine("Dequeue: " + numbers.Dequeue());

        // Check if the Queue is empty
        Console.WriteLine("Is the Queue empty? " + (numbers.Count == 0 ? "Yes" : "No"));
    }
}
```
